101:  * Spawns a new Node.js process + fork.
102:  * @param {string|URL} modulePath
103:  * @param {string[]} [args]
104:  * @param {{
105:  *   cwd?: string | URL;
106:  *   detached?: boolean;
107:  *   env?: Record<string, string>;
108:  *   execPath?: string;
109:  *   execArgv?: string[];
110:  *   gid?: number;
111:  *   serialization?: string;
112:  *   signal?: AbortSignal;
113:  *   killSignal?: string | number;
114:  *   silent?: boolean;
115:  *   stdio?: Array | string;
116:  *   uid?: number;
117:  *   windowsVerbatimArguments?: boolean;
118:  *   timeout?: number;
119:  *   }} [options]
